// src/App.jsx
import { useState } from 'react';
import './styles/global.css';

import Accueil    from './pages/Accueil';
import Sortie     from './pages/Sortie';
import Recherche  from './pages/Recherche';
import Articles   from './pages/Articles';
import Aides      from './pages/Aides';
import OrderForm  from './pages/OrderForm';
import Etats      from './pages/Etats';

const PAGES = {
  accueil:   Accueil,
  sortie:    Sortie,
  recherche: Recherche,
  articles:  Articles,
  aides:     Aides,
  orderform: OrderForm,
  etats:     Etats,
};

export default function App() {
  const [page, setPage] = useState('accueil');

  const PageComponent = PAGES[page] || Accueil;

  // OrderForm a son propre fond — pas de wrapper app-container
  if (page === 'orderform' || page === 'etats') {
    if (page === 'orderform') return <OrderForm navigate={setPage} />;
    return <Etats navigate={setPage} />;
  }

  return (
    <div className="app-container">
      <PageComponent navigate={setPage} />
    </div>
  );
}
